actions.script:
import groovy.json.JsonOutput
// DJL classes are NOT imported here — they are resolved at runtime via fully-qualified names
// so that moqui can compile this script at startup even when DJL JARs are absent.
// Place the required JARs in runtime/component/moqui-device/lib/ or runtime/lib/:
//   ai.djl:api:0.31.0
//   ai.djl.onnxruntime:onnxruntime-engine:0.31.0
//   com.microsoft.onnxruntime:onnxruntime:1.18.0

long t0 = System.currentTimeMillis()

// load MathModel + ONNX content location
EntityValue mathModel = ec.entity.find("moqui.math.MathModel").condition("mathModelId", mathModelId).one()
if (!mathModel) {
    ec.message.addError("MathModel ${mathModelId} not found")
    return
}

EntityValue onnxContent = ec.entity.find("moqui.math.MathModelDefContent")
    .condition("mathModelDefId", mathModel.mathModelDefId)
    .condition("contentTypeEnumId", "MmCntOnnx")
    .list().first()
if (!onnxContent) {
    ec.message.addError("No ONNX content for MathModelDef ${mathModel.mathModelDefId}")
    return
}

// open MathModelRun
EntityValue runVal = ec.entity.makeValue("moqui.math.MathModelRun")
    .setAll([mathModelId : mathModelId, startTime : ec.user.nowTimestamp,
        parameters : JsonOutput.toJson([startConfig: startConfig, goalConfig : goalConfig]),
        hasError : 'N'])
runVal.setSequencedIdPrimary()
runVal.create()
String runId = runVal.mathModelRunId

// DJL ONNX inference
// all DJL class references use fully-qualified names so the script compiles
// without DJL on the classpath (Groovy resolves them at runtime).
float[] rawOutput
int nWaypoints
long inferenceLatencyMs = 0L
def onnxModel = null
def manager = null
def predictor = null
File tempOnnx = null
File tempDataFile = null
java.nio.file.Path tempDir = null
try {
    // Copy ONNX to a temp directory preserving the original filename.
    // Reason 1: getUrl() returns jar: URLs in WAR deployments — Paths.get(uri) fails.
    // Reason 2: PyTorch 2.x may export external data ({name}.onnx + {name}.onnx.data);
    //     ONNX Runtime resolves the .data file relative to the .onnx location,
    //     so both files must live in the same directory with their original names.
    String origName = onnxContent.contentLocation.substring(
        onnxContent.contentLocation.lastIndexOf('/') + 1) // "trajectory_planner.onnx"
    String modelName = origName.replaceAll('\\.onnx$', '') // "trajectory_planner"
    tempDir = java.nio.file.Files.createTempDirectory("djl-onnx-")
    tempOnnx = new File(tempDir.toFile(), origName)
    ec.resource.getLocationReference(onnxContent.contentLocation).openStream()
        .withStream { inp -> tempOnnx.withOutputStream { out -> out << inp } }
    // Copy companion .data file if it exists (PyTorch external data format)
    try {
        EntityValue dataRef = ec.resource.getLocationReference(onnxContent.contentLocation + ".data")
        dataRef.openStream().withStream { inp ->
            tempDataFile = new File(tempDir.toFile(), origName + ".data")
            tempDataFile.withOutputStream { out -> out << inp }
        }
    } catch (Exception ignored) {}

    manager = ai.djl.ndarray.NDManager.newBaseManager("OnnxRuntime")
    onnxModel = ai.djl.Model.newInstance(modelName, "OnnxRuntime")
    onnxModel.load(tempDir, modelName)
    predictor = onnxModel.newPredictor(new ai.djl.translate.NoopTranslator())

    float[] inputData = new float[12]
    for (int i = 0; i < 6; i++) {
        inputData[i] = (float) (startConfig.get(i) as double)
        inputData[6 + i] = (float) (goalConfig.get(i)  as double)
    }

    def inputArr = manager.create(inputData, new ai.djl.ndarray.types.Shape(1L, 12L))
    long tInfer = System.currentTimeMillis()
    def outList = predictor.predict(new ai.djl.ndarray.NDList(inputArr))
    inferenceLatencyMs = System.currentTimeMillis() - tInfer
    rawOutput = outList.get(0).toFloatArray()
    nWaypoints = rawOutput.length / 6
} catch (NoClassDefFoundError | ClassNotFoundException djlMissing) {
    ec.message.addError("DJL JARs not found on classpath. Place api-0.31.0.jar, onnxruntime-engine-0.31.0.jar and onnxruntime-1.18.0.jar in runtime/component/moqui-device/lib/ and restart.")
    return
} catch (Exception ex) {
    long elapsed = System.currentTimeMillis() - t0
    EntityValue runRef = ec.entity.find("moqui.math.MathModelRun").condition("mathModelRunId", runId).one()
    runRef.setAll([endDate : ec.user.nowTimestamp, runningTimeMillis: (float) elapsed,
        hasError : 'Y', errors : ex.getMessage()])
    runRef.update()
    ec.message.addError("Trajectory inference failed: ${ex.getMessage()}")
    return
} finally {
    if (predictor) predictor.close()
    if (onnxModel) onnxModel.close()
    if (manager) manager.close()
    if (tempDataFile?.exists()) tempDataFile.delete()
    if (tempOnnx?.exists()) tempOnnx.delete()
    if (tempDir != null) tempDir.toFile().delete()
}

// persist ApproximatedFunction -> ParametricPath -> Trajectory

String label = trajectoryName ?: "AI Trajectory ${runId}"

EntityValue afVal = ec.entity.makeValue("moqui.math.ApproximatedFunction")
    .setAll([vectorSpaceEnumId : "EngJointSpace6Dof", codomainTypeEnumId : "AfctVector",
        dataStorageEnumId : "AfdsPointTable", purposeEnumId : "AfpRobotMotion",
        interpolationEnumId : "AfiAIPath", name : label,
        description : "6-DOF robot trajectory from MLP planner"])
afVal.setSequencedIdPrimary()
afVal.create()
String afId = afVal.approximatedFunctionId

ec.entity.makeValue("moqui.math.ParametricPath").setAll([approximatedFunctionId: afId,
    profileEnumId : "PppfTrajectoryProfile"]).create()

ec.entity.makeValue("moqui.math.Trajectory").setAll([approximatedFunctionId: afId,
    actuationTypeEnumId : "PtaDirect", actuatorTypeEnumId : "PtactRevolute",
    controlMethodEnumId : "PtcmNNControl"]).create()

// persist waypoints

double stepMs = nWaypoints > 1 ? 1000.0 / (nWaypoints - 1) : 0.0

for (int i = 0; i < nWaypoints; i++) {
    // Vector for this waypoint's joint positions
    EntityValue vecVal = ec.entity.makeValue("moqui.math.Vector")
        .setAll([vectorTypeEnumId: "VtOrdinary", purposeEnumId : "VpPosition", dimension : 6])
    vecVal.setSequencedIdPrimary()
    vecVal.create()
    String vecId = vecVal.vectorId

    // 6 VectorComponents (one per joint)
    for (int j = 0; j < 6; j++) {
        EntityValue compVal = ec.entity.makeValue("moqui.math.VectorComponent")
            .setAll([vectorId : vecId, dimensionIndex : j, componentTypeEnumId : "VctCanonical",
            realValue : (double) rawOutput[i * 6 + j]])
        compVal.setSequencedIdPrimary()
        compVal.create()
    }

    String sampleType = (i == 0) ? "AfstStartPoint"
        : (i == nWaypoints - 1) ? "AfstEndPoint"
        : "AfstWaypoint"

    EntityValue sampleVal = ec.entity.makeValue("moqui.math.ApproximatedFunctionSample")
        .setAll([approximatedFunctionId: afId, sampleCode : "WP${String.format('%04d', i)}",
            sampleName : "Waypoint ${i}", sequenceNum : i,
            sampleTypeEnumId : sampleType, sampleVectorId : vecId])
    sampleVal.setSequencedIdSecondary()
    sampleVal.create()
    String sampleId = sampleVal.approximatedFunctionSampleId

    ec.entity.makeValue("moqui.math.ParametricPathPoint")
        .setAll([approximatedFunctionId : afId,
            approximatedFunctionSampleId : sampleId]).create()

    ec.entity.makeValue("moqui.math.TrajectoryPoint")
        .setAll([approximatedFunctionId : afId,
            approximatedFunctionSampleId : sampleId,
            pointTimeOffsetMillis : i * stepMs]).create()
}

// persist input vectors (q_start / q_goal)

EntityValue startVecVal = ec.entity.makeValue("moqui.math.Vector")
    .setAll([vectorTypeEnumId: "VtOrdinary", purposeEnumId: "VpPosition",
        dimension: 6, name: "q_start"])
startVecVal.setSequencedIdPrimary()
startVecVal.create()
String startVecId = startVecVal.vectorId
for (int j = 0; j < 6; j++) {
    EntityValue c = ec.entity.makeValue("moqui.math.VectorComponent")
        .setAll([vectorId: startVecId, dimensionIndex: j,
            componentTypeEnumId: "VctCanonical", realValue: (startConfig.get(j) as double)])
    c.setSequencedIdPrimary(); c.create()
}

EntityValue goalVecVal = ec.entity.makeValue("moqui.math.Vector")
    .setAll([vectorTypeEnumId: "VtOrdinary", purposeEnumId: "VpPosition", dimension: 6, name: "q_goal"])
goalVecVal.setSequencedIdPrimary()
goalVecVal.create()
String goalVecId = goalVecVal.vectorId
for (int j = 0; j < 6; j++) {
    EntityValue c = ec.entity.makeValue("moqui.math.VectorComponent")
        .setAll([vectorId: goalVecId, dimensionIndex: j,
            componentTypeEnumId: "VctCanonical",
            realValue: (goalConfig.get(j) as double)])
    c.setSequencedIdPrimary(); c.create()
}

// MathModelData — output trajectory + input vectors

EntityValue outData = ec.entity.makeValue("moqui.math.MathModelData")
    .setAll([mathModelId : mathModelId, dataTypeEnumId : "MmdtApproxFunc",
        purposeEnumId : "MmdpModelOutputs", generatedByRunId : runId,
        approximatedFunctionId : afId, sequenceNum : 1])
outData.setSequencedIdPrimary(); outData.create()

EntityValue startData = ec.entity.makeValue("moqui.math.MathModelData")
    .setAll([mathModelId : mathModelId, dataTypeEnumId : "MmdtVector",
        purposeEnumId : "MmdpModelInputs", generatedByRunId : runId,
        vectorId : startVecId, sequenceNum : 2])
startData.setSequencedIdPrimary(); startData.create()

EntityValue goalData = ec.entity.makeValue("moqui.math.MathModelData")
    .setAll([mathModelId : mathModelId, dataTypeEnumId : "MmdtVector",
        purposeEnumId : "MmdpModelInputs", generatedByRunId : runId,
        vectorId : goalVecId, sequenceNum : 3])
goalData.setSequencedIdPrimary(); goalData.create()

// close MathModelRun

long elapsed = System.currentTimeMillis() - t0

EntityValue runRef = ec.entity.find("moqui.math.MathModelRun")
    .condition("mathModelRunId", runId).one()
runRef.setAll([endDate : ec.user.nowTimestamp, runningTimeMillis : (float) elapsed,
    approximatedFunctionId: afId, results : JsonOutput.toJson([approximatedFunctionId: afId,
    waypointCount : nWaypoints])])
runRef.update()

// MathModelPerf

EntityValue perfVal = ec.entity.makeValue("moqui.math.MathModelPerf")
    .setAll([mathModelRunId      : runId,
             totalDurationSec    : elapsed / 1000.0 as double,
             inferenceLatencyMs  : inferenceLatencyMs as double,
             throughputSamplesSec: nWaypoints / (elapsed / 1000.0) as double])
perfVal.setSequencedIdPrimary()
perfVal.create()

// output parameters

mathModelRunId = runId
approximatedFunctionId = afId
mathModelPerfId = perfVal.mathModelPerfId
